import { Component, EventEmitter, Prop, h, Event } from '@stencil/core';
import { CrossIcon } from '../../svg/Svg';

@Component({
  tag: 'chip-component',
  styleUrl: 'chip-component.css',
  shadow: true,
})
export class ChipComponent {

  @Prop() label: string;
  @Prop() rounded: boolean = true;
  @Prop() height: string = '32px';
  @Prop() showIcon: boolean = false;
  @Event() chipClose: EventEmitter<void>;
  @Prop() selectable: boolean = false;
  @Prop({ mutable: true, reflect: true }) selected: boolean = false;
  @Event() chipSelect: EventEmitter<boolean>;
  @Prop() colors?: string;
  @Prop() maxWidth?: string;


  handleClose = (e: MouseEvent) => {
    e.stopPropagation();
    this.chipClose.emit();
  };

  handleSelect = () => {
    if (!this.selectable) return;
    this.selected = !this.selected;
    this.chipSelect.emit(this.selected);
  };

  private getColors(): string[] {
    if (!this.colors) return [];
    return this.colors.split(',').map(c => c.trim());
  }

  renderIcon() {
    if (!this.showIcon) return null;
    return (
      <button
        class="chip-icon"
        onClick={this.handleClose}
        aria-label="Remove"
        type="button"
        tabindex={0}
      >
        <CrossIcon className="cross-icon" />
      </button>
    );
  }

  render() {
    return (
      <div
        class={{
          chip: true,
          rounded: this.rounded,
          selectable: this.selectable,
          selected: this.selected,
        }}
        style={{
          height: this.height,
          width: 'auto',
          cursor: this.selectable ? 'pointer' : 'default',
          ...(this.maxWidth
            ? { maxWidth: this.maxWidth, width: '100%', minWidth: '0' }
            : { width: 'auto' })
        }}
        onClick={this.handleSelect}
        tabindex={this.selectable ? 0 : undefined}
        aria-pressed={this.selectable ? String(this.selected) : undefined}
      >
        {this.getColors().length === 3 && (
          <div class="color-swatch">
            {this.getColors().map(color => (
              <div class="swatch-color" style={{ background: color }}></div>
            ))}
          </div>
        )}
        <span class="chip-label">{this.label}</span>
        {!this.selectable && this.renderIcon()}
      </div>
    );
  }


}
